package main

import "math"

// SegmentTree structure tailored for Range Maximum Query and Point Update,
// operating on the value domain [1, V_MAX].
type SegmentTree struct {
	V_MAX int
	tree  []int64
}

func NewSegmentTree(vMax int) *SegmentTree {
	return &SegmentTree{
		V_MAX: vMax,
		tree:  make([]int64, 4*vMax+5),
	}
}

// Update the score associated with a specific value index `valIndex`.
// Stores the maximum score seen for that value index.
func (st *SegmentTree) Update(valIndex int, score int64) {
	st._updateRec(1, 1, st.V_MAX, valIndex, score)
}

func (st *SegmentTree) _updateRec(node, start, end, idx int, score int64) {
	if start == end {
		// Leaf node reached. Update only if the new score is higher.
		st.tree[node] = int64(math.Max(float64(st.tree[node]), float64(score)))
		return
	}

	mid := start + (end-start)/2

	if idx <= mid {
		st._updateRec(2*node, start, mid, idx, score)
	} else {
		st._updateRec(2*node+1, mid+1, end, idx, score)
	}

	// Update internal node by taking the max of children
	st.tree[node] = int64(math.Max(float64(st.tree[2*node]), float64(st.tree[2*node+1])))
}

// Query the maximum score in the value range [L, R].
func (st *SegmentTree) Query(L, R int) int64 {
	if L > R || L < 1 || R > st.V_MAX {
		return 0 // Neutral element for max operation
	}
	return st._queryRec(1, 1, st.V_MAX, L, R)
}

func (st *SegmentTree) _queryRec(node, start, end, L, R int) int64 {
	// Range represented by node is outside the query range
	if start > R || end < L {
		return 0
	}

	// Range represented by node is completely inside the query range
	if L <= start && end <= R {
		return st.tree[node]
	}

	// Partial overlap
	mid := start + (end-start)/2

	p1 := st._queryRec(2*node, start, mid, L, R)
	p2 := st._queryRec(2*node+1, mid+1, end, L, R)

	return int64(math.Max(float64(p1), float64(p2)))
}

