/**
 * Helper class for Segment Tree implementation supporting Range Maximum Query (RMQ) and Point Update.
 * The tree is 1-indexed based on the value domain [1, V_MAX].
 */
class SegmentTree {
    constructor(V_MAX) {
        this.V_MAX = V_MAX;
        // Tree size is usually 4 * V_MAX + buffer
        this.tree = new Array(4 * V_MAX + 5).fill(0);
    }

    // Update the score associated with a specific value index `val_index`
    // We store the maximum score seen for that value index.
    update(val_index, score) {
        this._updateRec(1, 1, this.V_MAX, val_index, score);
    }

    _updateRec(node, start, end, idx, score) {
        if (start === end) {
            // Leaf node reached. Update only if the new score is higher.
            this.tree[node] = Math.max(this.tree[node], score);
            return;
        }

        const mid = Math.floor((start + end) / 2);

        if (idx <= mid) {
            this._updateRec(2 * node, start, mid, idx, score);
        } else {
            this._updateRec(2 * node + 1, mid + 1, end, idx, score);
        }

        // Update internal node by taking the max of children
        this.tree[node] = Math.max(this.tree[2 * node], this.tree[2 * node + 1]);
    }

    // Query the maximum score in the value range [L, R]
    query(L, R) {
        if (L > R) return 0;
        return this._queryRec(1, 1, this.V_MAX, L, R);
    }

    _queryRec(node, start, end, L, R) {
        // Range represented by node is outside the query range
        if (start > R || end < L) {
            return 0; // Neutral element for max operation
        }

        // Range represented by node is completely inside the query range
        if (L <= start && end <= R) {
            return this.tree[node];
        }

        // Partial overlap
        const mid = Math.floor((start + end) / 2);

        const p1 = this._queryRec(2 * node, start, mid, L, R);
        const p2 = this._queryRec(2 * node + 1, mid + 1, end, L, R);

        return Math.max(p1, p2);
    }
}


function solve(nums, k) {
    const N = nums.length;
    if (N === 0) return 0;

    // V_MAX is the maximum possible value in nums
    const V_MAX = 100000;

    // Up[i]: Max score ending at i, where nums[i] is greater than previous element (Peak)
    const Up = new Array(N).fill(0);
    // Down[i]: Max score ending at i, where nums[i] is smaller than previous element (Valley)
    const Down = new Array(N).fill(0);

    // ST_Down stores max(Down[j]) indexed by nums[j]
    const ST_Down = new SegmentTree(V_MAX);
    // ST_Up stores max(Up[j]) indexed by nums[j]
    const ST_Up = new SegmentTree(V_MAX);

    let maxScore = 0;

    for (let i = 0; i < N; i++) {
        const num_i = nums[i];

        // 1. Activation Phase (Data Insertion): Make results from index i-k available
        if (i >= k) {
            const j = i - k;

            // Insert DP[j] into the Segment Trees
            // Note: We use the calculated Up[j] and Down[j] values from previous iterations.

            // Update ST_Down: Score associated with valley ending at j
            ST_Down.update(nums[j], Down[j]);

            // Update ST_Up: Score associated with peak ending at j
            ST_Up.update(nums[j], Up[j]);
        }

        // 2. Calculation Phase (DP Update)

        // Length 1 subsequence always valid
        Up[i] = num_i;
        Down[i] = num_i;

        // Calculate Up[i]: Predecessor j must be a Valley (Down[j]), and nums[j] < nums[i]
        // Query range for nums[j]: [1, num_i - 1]
        const L_Down = ST_Down.query(1, num_i - 1);
        if (L_Down > 0) {
            Up[i] = Math.max(Up[i], num_i + L_Down);
        }

        // Calculate Down[i]: Predecessor j must be a Peak (Up[j]), and nums[j] > nums[i]
        // Query range for nums[j]: [num_i + 1, V_MAX]
        const L_Up = ST_Up.query(num_i + 1, V_MAX);
        if (L_Up > 0) {
            Down[i] = Math.max(Down[i], num_i + L_Up);
        }

        // 3. Result Update
        maxScore = Math.max(maxScore, Up[i], Down[i]);
    }

    return maxScore;
}
